from typing import Literal

BACKEND_MAP = {
    'scalar':     ('halmos_check',     'check_'),
    'relational': ('halmos_ghost_hook', 'check_'),  # ghost-shim emitted into setUp + test
    'temporal':   ('halmos_invariant',  'invariant_'),  # uses --invariant-depth
    'counting':   ('halmos_ghost_hook', 'check_'),  # ghost mapping + hook
    'manifold':   ('echidna_property',  'echidna_'),  # property test, not symbolic
    'null':       ('none',              None),
}

def route(invariant: dict) -> dict:
    mode = invariant['representation_mode']
    backend, prefix = BACKEND_MAP[mode]
    # also check existing TLA+ shape match: if invariant maps to a docs/tla/*.tla shape,
    # ALSO emit a TLC discharge as a second corroborating signal
    if invariant.get('tla_shape_match'):
        return {
            'primary': backend,
            'primary_prefix': prefix,
            'secondary': 'tlc_temporal',
            'tla_module': invariant['tla_shape_match'],
        }
    return {'primary': backend, 'primary_prefix': prefix}

def emit_test(invariant: dict, target_function_src: str) -> str:
    mode = invariant['representation_mode']
    if mode == 'scalar':
        return f'function check_{invariant["name"]}() public {{\n    // ...\n    assert({invariant["assertion"]["scalar_expr"]});\n}}'
    elif mode == 'relational':
        rel = invariant['assertion']['relational_expr']
